   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
   if (Instruction *Result = commonCastTransforms(Trunc))
     return Result;
@@ -816,6 +817,15 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     }

     Constant *C;
+    // If we have trunc nuw (lshr X, SrcWidth-1), we can convert to icmp slt X, 0
+    // because the nuw flag guarantees the source value is 0 or 1, which corresponds
+    // to the sign bit.
+    if (Trunc.hasNoUnsignedWrap() &&
+        match(Src, m_LShr(m_Value(X), m_ImmConstant(C))) &&
+        C->getUniqueInteger() == SrcWidth - 1) {
+      return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
+    }
+    
     if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
       // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
@@ -962,6 +972,7 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
   return Changed ? &Trunc : nullptr;
 }

